Điều hướng bên trong Component<pre><code>import { useNavigate } from 'react-router-dom';

function ProductCard({ id }: { id: number }) {
  const navigate = useNavigate();

  const handleClick = () =&gt; {
    // Điều hướng đến trang chi tiết
    navigate(`/products/${id}`);

    // Truyền thêm state
    // navigate('/checkout', { state: { productId: id } });

    // Thay thế (replace: không lưu vào lịch sử)
    // navigate('/home', { replace: true });
  };

  return &lt;button onClick={handleClick}&gt;Xem chi tiết&lt;/button&gt;;
}
</code></pre>

useParams (Path params)useSearchParams (Query params) <p>Lấy giá trị từ dynamic segment (ví dụ <code>:id</code>). <pre><code>import { useParams } from 'react-router-dom';

// Route: /products/:category/:id
function ProductDetail() {
  const { category, id } = useParams&lt;{ category: string; id: string }&gt;();
  return &lt;h1&gt;Chuyên mục {category} - Sản phẩm #{id}&lt;/h1&gt;;
}
</code></pre></p> <p>Quản lý query string (<code>?key=value</code>). <pre><code>import { useSearchParams } from 'react-router-dom';

function ProductList() {
  const [searchParams, setSearchParams] = useSearchParams();
  const page = searchParams.get('page') ?? '1';

  const nextPage = () =&gt; setSearchParams({ page: String(Number(page) + 1) });

  return &lt;button onClick={nextPage}&gt;Trang sau&lt;/button&gt;;
}
</code></pre></p>

src/state.ts — Listing atoms<pre><code>import { atom } from 'jotai';
import type { Service, Doctor } from './types';

// Atom chứa Promise → tương thích Suspense tự nhiên
export const servicesState = atom&lt;Promise&lt;Service[]&gt;&gt;(fetchServices());
export const doctorsState = atom&lt;Promise&lt;Doctor[]&gt;&gt;(fetchDoctors());
</code></pre> <p>Tại sao dùng <code>atom&lt;Promise&lt;T&gt;&gt;</code>? Jotai + React Suspense hiểu khi atom trả về Promise, component sẽ tự suspend cho đến khi data ready — không cần <code>isLoading</code> state thủ công.</p>

src/state.ts — Detail atoms<pre><code>import { atomFamily } from 'jotai/utils';

// Tạo atom riêng cho từng ID
// atomFamily caches kết quả → gọi serviceByIdState(1) nhiều lần = chỉ 1 atom
export const serviceByIdState = atomFamily((id: number) =&gt;
  atom(async (get) =&gt; {
    const services = await get(servicesState);
    return services.find((s) =&gt; s.id === id);
  })
);

// Dùng trong component
function ServiceDetail({ id }: { id: number }) {
  const service = useAtomValue(serviceByIdState(id));
  return &lt;h1&gt;{service?.name}&lt;/h1&gt;;
}
</code></pre>

src/state.ts — Form atoms<pre><code>import { atomWithReset } from 'jotai/utils';
import { useResetAtom } from 'jotai/utils';

export const bookingFormState = atomWithReset&lt;BookingForm&gt;({
  symptoms: [],
  description: '',
  images: [],
});

// Reset về giá trị ban đầu sau khi submit
function BookingForm() {
  const resetForm = useResetAtom(bookingFormState);

  const handleSubmit = async () =&gt; {
    await submitBooking();
    resetForm(); // ← Sạch form, không cần setForm({symptoms:[], ...})
  };
}
</code></pre>

src/state.ts — Refreshable atom<pre><code>import { atomWithRefresh } from 'jotai/utils';
import { getUserInfo } from 'zmp-sdk';

// Atom có thể trigger refetch từ bên ngoài
export const userState = atomWithRefresh(() =&gt;
  getUserInfo({ avatarType: 'normal' })
    .catch(() =&gt; { throw new Error('Vui lòng cho phép truy cập!'); })
);

// Dùng trong component
function UserProfile() {
  const [user, refreshUser] = useAtom(userState);

  return (
    &lt;div&gt;
      &lt;img src={user.avatar} /&gt;
      &lt;button onClick={refreshUser}&gt;Làm mới&lt;/button&gt;
    &lt;/div&gt;
  );
}
</code></pre>

src/state.ts — Loadable pattern<pre><code>import { loadable } from 'jotai/utils';

// Wrap async atom vào loadable → không cần Suspense boundary
export const searchResultState = atomFamily((keyword: string) =&gt;
  loadable(
    atom(async (get) =&gt; {
      const doctors = await get(doctorsState);
      return doctors.filter(d =&gt; d.name.includes(keyword));
    })
  )
);

// Trong component
function SearchResult({ keyword }: { keyword: string }) {
  const result = useAtomValue(searchResultState(keyword));

  if (result.state === 'loading') return &lt;Spinner /&gt;;
  if (result.state === 'hasError') return &lt;ErrorMessage /&gt;;
  return &lt;List data={result.data} /&gt;;
}
</code></pre>

src/app.ts — Entry point<pre><code>import { createRoot } from 'react-dom/client';
import { Provider } from 'jotai';
import Layout from './components/layout';

createRoot(document.getElementById('app')!).render(
  // Provider phải ở NGOÀI MemoryRouter
  // để state không bị reset khi navigate
  &lt;Provider&gt;
    &lt;Layout /&gt;
  &lt;/Provider&gt;
);
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Giao Thức Liên Lạc (Data Streams)</p> <p>Trong mũ giáp, <code>String</code> không chỉ là văn bản. Nó là mã lệnh giao tiếp hiện lên mặt kính HUD chữ xanh <code>Neon Cyan</code>. </p> <p>Template Literals (dấu backtick <code>`</code>) chính là các Khe cắm Module. Khi báo tọa độ cho đồng đội, biến số bay vào vị trí <code>${}</code> và khớp lại với tiếng "click" cơ khí thỏa mãn. Ráp sai module sẽ bị hệ thống báo lỗi ngay lập tức.</p> <p>Trong JS, chuỗi rất dễ gây lỗi nếu đem cộng với số (vd: <code>"Sector " + 7</code>). Trong TypeScript, <code>string</code> ép kiểu chặt chẽ từ dòng code đầu tiên.</p> <pre><code>// Khai báo rõ ràng đây là dữ liệu văn bản
let sector: string = "7"; 

// Sử dụng Template Literal an toàn tuyệt đối
let message: string = `Approaching Sector ${sector}`; 

// Báo lỗi ngay lập tức ở lúc viết code (Compile time)
// message = 100; // Error: Type 'number' is not assignable to type 'string'
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Chỉ Số Năng Lượng (Energy/Ballistics)</p> <p>Sự chính xác của <code>Number</code> quyết định sống còn. Việc tính toán sai lệch quỹ đạo đạn sẽ làm vũ khí kẹt hoặc nổ tung.  Nếu bạn cố tình nạp đạn bằng "chữ" (Text) vào súng, màn hình HUD sẽ nhấp nháy đỏ rực kèm cảnh báo:  TYPE MISMATCH: CANNOT LOAD TEXT INTO BALLISTICS CALCULATOR.</p> <p>JS quy mọi số về IEEE 754 floating point. TypeScript bảo vệ tính toàn vẹn toán học bằng việc khóa kiểu biến ở dạng <code>number</code> (hỗ trợ cả int, float, hex, binary).</p> <pre><code>let ammoCount: number = 250;
let shieldIntegrity: number = 98.5;
let hexKey: number = 0xf00d; // Hỗ trợ hệ thập lục phân

// Tự tin làm toán mà không sợ Type Coercion kỳ quặc của JS
let currentPower: number = ammoCount + shieldIntegrity;

// ammoCount = "Empty"; // Báo lỗi: không thể truyền string vào number
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Hệ Thống An Toàn (Safety Switches)</p> <p>Công tắc gạt ảo trên HUD.  Màu Xanh lá (true): Hệ thống vũ khí Online.  Màu Đỏ (false): Khóa an toàn / Tàng hình. Nếu công tắc lỏng lẻo, bạn nhấn nhầm nút "0" hoặc "" (falsy trong JS gốc), khiên năng lượng có thể tắt phụt ngay giữa trận.</p> <p>Boolean trong TS chỉ thuần túy nhận <code>true</code> hoặc <code>false</code>, diệt trừ tận gốc các lỗi so sánh lỏng lẻo do Truthy/Falsy của JavaScript tạo ra.</p> <pre><code>let isShieldsUp: boolean = true;
let isEngaged: boolean = false;

if (isShieldsUp) {
    console.log("An toàn.");
}

// JS cho phép, nhưng TS sẽ cấm:
// isShieldsUp = 1; // Error: Type 'number' is not assignable to type 'boolean'.
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>CHẾ ĐỘ CUỒNG NỘ: KÍCH HOẠT</p> <p>Dùng <code>Any</code> nghĩa là bạn vứt bỏ bộ giáp bảo vệ. Màn hình HUD bị nhiễu (Glitch), chuyển đỏ báo động. Thông báo chớp tắt: SAFETY PROTOCOLS DISABLED. Bạn có thể code cực nhanh, nhưng hệ thống radar cảnh báo rủi ro xung quanh đã tắt ngúm. Một đòn chí mạng Runtime Error có thể kết liễu bạn lúc nào không hay.</p> <p><code>any</code> là con dao hai lưỡi. Nó tắt hoàn toàn quá trình Type Checking của TS, đưa code trở về JS thông thường. Đừng bao giờ lạm dụng cấu trúc này trừ khi bạn thực sự phải làm việc với các hệ thống legacy hoặc dữ liệu thô chưa rõ hình thù.</p> <pre><code>let unknownEntity: any = "Biến hình";

unknownEntity = 42; // Vượt rào thành công
unknownEntity = true; // Vượt rào thành công

// Dù không tồn tại, trình biên dịch vẫn nhắm mắt cho qua!
// Nhưng TẠI RUNTIME SẼ CRASH!
// unknownEntity.flyToTheMoon(); 
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Lệnh Xả Nhiệt</p> <p>Khi Ronin ra lệnh "Khởi động bộ đẩy" (<code>activateThrusters()</code>), năng lượng cháy bừng, phản lực đẩy vọt lên. Hàm này chỉ thực thi thao tác, không trả lại bất cứ vật thể nào. Giống như bắn một viên đạn: Đạn bay đi, chứ đạn không găm ngược trở lại tay người bắn. Lệnh báo EXECUTION COMPLETE.</p> <p><code>void</code> thường dùng để định nghĩa giá trị trả về của hàm không có dữ liệu trả về (thường chứa thao tác bên lề <code>side-effects</code> như ghi log, đổi DOM...).</p> <pre><code>// Hàm này chỉ thực hiện công việc, không có lệnh return giá trị dữ liệu
function logCombatData(enemyName: string): void {
    console.log(`Đã lưu dữ liệu chiến đấu của ${enemyName} vào hộp đen.`);
    // return 123; // Error: Type 'number' is not assignable to type 'void'.
}

logCombatData("Scavenger_01");
</code></pre> <p>Nhiệm vụ tiếp theo: Bạn đã học cách tạo Lò phản ứng <code>tsc</code> và gắn 5 mô-đun sinh tồn. Trạm tiếp theo: Module 02: Khung Giáp Exosuit (OOP) để đúc lớp vỏ bảo vệ.</p>

🎭 Cyber-Metaphor💻 Tech Specs <p>Lớp Giáp Ngoại Vi (External Hardpoints)</p> <p>Mọi <code>public</code> modifier tương đương với Điểm Gắn Vũ Khí (Muzzle), ăng-ten liên lạc, cờ hiệu sau lưng Ronin.  Mọi người đều thấy nó. Kẻ thù có thể chém vào nó. Đồng minh có thể giao tiếp qua nó. Sự minh bạch là cần thiết, nhưng phơi bày quá nhiều là tử huyệt.</p> <p>Cấu hình mặc định của TypeScript (như JS) là <code>public</code>.  Tầm nhìn: Có thể truy cập mọi nơi (Tạo instance xong xài được ngay).</p> <pre><code>class Exosuit {
    // Radar ngoài, ai cũng có thể ping
    public callSign: string; 

    constructor(sign: string) {
        this.callSign = sign;
    }

    // Tương tác ngoại vi: Bóp cò súng
    public engageTarget(): void {
        console.log(`[${this.callSign}] Khai hỏa!`);
    }
}

const mech = new Exosuit("Alpha-1");
mech.engageTarget(); // Hợp lệ, public mà!
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Hệ Thống Nội Tại Dễ Bay Hơi</p> <p>Nhịp tim phi công, Nhiệt độ Lò phản ứng nhiệt hạch. Bộ giáp CẦN biết để vận hành. Nhưng thằng bạn đứng cạnh tuyệt đối không được quyền chạm chĩa vào để điều chỉnh thanh làm mát của bạn.</p> <p>Ảo ảnh của <code>private</code>: Đây là tấm biển dán trên vỏ giáp ghi chữ "CẤM SỜ". Giới quý tộc (Trình biên dịch TSC) tuân thủ luật lệ này. Nhưng lũ Scavengers (Hacker dùng JS tại Runtime) hoàn toàn có thể bóc biển bạo lực thò tay vào.</p> <p><code>private</code> chỉ KIỂM TRA TẠI THỜI ĐIỂM BIÊN DỊCH (Compile-time). Tầm nhìn: Chết đứng trong Class, cấm ngặt truy cập từ ngoài hay Subclass.</p> <pre><code>class Exosuit {
    // Tấm biển "Cấm sờ"
    private _fusionCoreTemp: number = 2000;

    private ventPlasma(): void {
        console.log("Xả nhiệt khẩn cấp!");
    }

    public regulateSystem(): void {
        if (this._fusionCoreTemp &gt; 5000) this.ventPlasma();
    }
}

const suit = new Exosuit();
// suit._fusionCoreTemp = 6000; // LỖI COMPILER: Thuộc tính private!

// NHƯNG khi dịch ra JS thông thường, nó lại hợp lệ: 
// suit._fusionCoreTemp = 6000; (JS runtime chằng quan tâm biển cấm).
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Đóng Gói Hộp Đen Bọc Chì (Stealth Mode)</p> <p>Đây mới là sự bảo vệ hàng thật. Một khối dữ liệu tàng hình, hoàn toàn bất khả xâm phạm tại Runtime. Dành riêng cho Mã khóa An ninh, Token điều lệnh. Ngay cả khi Radar đối phương (Inspect) lướt qua, nó cũng vô hình.</p> <p>Dùng cú pháp <code>#</code> (Chuẩn ECMAScript) thay vì chữ <code>private</code> của TS. Dữ liệu này THỰC SỰ KHÓA KÍN TẠI RUNTIME trên engine JS V8. Lỗi syntax sẽ quăng thẳng mặt kẻ truy lậu.</p> <pre><code>class StealthSuit {
    // Cú pháp ECMAScript Hard-Private
    #encryptionKey: string; 

    constructor(key: string) {
        this.#encryptionKey = key;
    }

    public decrypt(msg: string) {
        return `Decrypted with ${this.#encryptionKey}`;
    }
}

const ninja = new StealthSuit("XYZ999");
// console.log(ninja.#encryptionKey); // SyntaxError Lập Tức! Không ai đọc được!
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Bí Kíp Võ Đường (Clan Tech)</p> <p>Một bản vẽ thiết kế Thủy lực chung (BaseArmor) có bí quyết nén dầu riêng. Cha (Base Class) chia sẻ nó cho Con (HeavyArmor, LightArmor) để Con sáng tạo tiếp trên nền tảng đó.  NHƯNG, bí kíp tuyệt đối KHÔNG lọt ra tay kẻ ngoại đạo (Cấm truy cập từ instance bên ngoài).</p> <p>Tầm nhìn: Vừa truy cập được trong Class cha, VỪA kế thừa dùng được trong Class con (Extends).</p> <pre><code>class BaseArmor {
    // Secret của dòng họ Armor
    protected armorIntegrity: number = 100; 
}

class HeavyArmor extends BaseArmor {
    public reinforce(): void {
        // Con nối nghiệp dùng đồ nghề của Cha
        this.armorIntegrity += 50; 
        console.log(`Độ bền tăng lên: ${this.armorIntegrity}`);
    }
}

const unit = new HeavyArmor();
unit.reinforce(); // Hợp lệ, gọi hàm public
// unit.armorIntegrity = 0; // LỖI! Kẻ ngoại đạo không được chạm vào.
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Con Dấu Niêm Phong (Factory Sealed)</p> <p>Số Serial Nhà Sản Xuất, Tải Trọng MAX. Những thông số được khắc Laze thủ công vào thẳng ROM (Read-Only Memory). Không một thế lực nào trên chiến trường làm mờ đi những vết khắc danh tính này.</p> <p>Thuộc tính TĨNH. Sau vòng đời Constructor xong xuôi, cấm chỉ định ghi đè lại suốt phần đời còn lại.</p> <pre><code>class Exosuit {
    // Khắc laze không cho đổi
    public readonly serialNumber: string;

    constructor(id: string) {
        this.serialNumber = id; // Hợp lệ: Lúc đúc trong lò được gán 1 lần
    }

    public updateFirmware() {
        // this.serialNumber = "Hacked-ID"; // LỖI HIỂN NHIÊN! Bị niêm phong rồi!
    }
}
</code></pre>

🎭 Cyber-Metaphor💻 Tech Specs <p>Khe cắm phụ kiện (Optional Slot)</p> <p>Dấu <code>?</code> đánh dấu đây là một Khe Cắm Mở. Phi công có quyền cắm Bùa Chú cường hóa hoặc bỏ trống. Tuy nhiên, Lò rèn sẽ tự động hiểu rằng nếu bỏ trống, giá trị bên trong sẽ là Không Khí (undefined). Do đó, phi công bắt buộc phải móc máy quét ra IF kiếm tra: “Khe này có đồ không?” trước khi truyền năng lượng vào, nếu không sẽ chập điện.</p> <p>Khi gắn <code>?</code>, TypeScript tự động ép kiểu tham số đó thành một dạng lai <code>Type | undefined</code>. Nó ép dev bạn phải xử lý cả tình huống giá trị bị bỏ quên.</p> <pre><code>function cuongHoaVuKhi(id: number, buaChu?: string): void {
    // BAT BUỘC KIỂM TRA vì buaChu có thể là undefined
    if (buaChu) {
        console.log(`Vũ khí ${id} được cường hóa bởi [${buaChu.toUpperCase()}]`);
    } else {
        console.log(`Vũ khí ${id} hoạt động ở trạng thái cơ sở.`);
    }
}

cuongHoaVuKhi(12); // Không truyền buaChu -&gt; Vẫn chạy tốt.
cuongHoaVuKhi(45, "Lửa Địa Ngục"); 
</code></pre>
